              >
                <UserPlus size={12} />
                <span>Add Law</span>
              </button>
            </div>

            {showAddLaw && (
              <form onSubmit={handleCreateLaw} className="p-3 bg-neutral-900 rounded border border-neutral-850 space-y-2">
                <input
