    const checkState = async () => {
      try {
        const res = await fetch('/api/config-status');
        if (res.ok) {
          const stats = await res.json();
          setDaoStatus(stats.hasServerGemini ? 'connected' : 'disconnected');
        } else {
          setDaoStatus('disconnected');
        }
      } catch {
        setDaoStatus('disconnected');
      }
    };
    checkState();
