    setIsClaiming(true);
    // Award Qi
    if (auth.currentUser) {
      await awardDirectQi(qiEarned, `idle-cultivation-${Date.now()}`);
    }

    // Update local profile instantly
    if (userProfile) {
      const updated = {
        ...userProfile,
        dao_xp: (userProfile.dao_xp || 0) + qiEarned,
        qi: (userProfile.qi || 0) + qiEarned,
      };
      setUserProfile(updated);
    }

    setTimeout(() => {
      setIsClaiming(false);
      onClose();
    }, 1500);
