  };

  const compositeGlossary = [...DEFAULT_CULTIVATION_GLOSSARY, ...customGlossary];
  const filteredGlossary = compositeGlossary.filter(item => 
    item.term.toLowerCase().includes(glossarySearch.toLowerCase()) ||
