export async function unlockCosmicArtifact(
  keyOrArtifact: string | Omit<CosmicArtifact, 'id' | 'unlockedAt'>,
  sourceId?: string,
  sourceTitle?: string
): Promise<CosmicArtifact | null> {
  const user = auth.currentUser;
  const now = new Date().toISOString();

  let baseArtifact: Omit<CosmicArtifact, 'id' | 'unlockedAt'>;
  let milestoneType: CosmicArtifact['milestoneType'];
  let milestoneName: string;
  let artifactKey = '';

  if (typeof keyOrArtifact === 'string') {
    artifactKey = keyOrArtifact;
    const template = COSMIC_ARTIFACT_TEMPLATES[keyOrArtifact as keyof typeof COSMIC_ARTIFACT_TEMPLATES];
    if (!template) return null;

    milestoneType = keyOrArtifact === 'chapter_seal' ? 'chapter_seal' :
                    keyOrArtifact === 'challenge_complete' ? 'challenge_complete' :
                    keyOrArtifact === 'chapter_5' ? 'first_breakthrough' :
                    [
                      'legendary_sword',
                      'boss_fight',
                      'bond_token',
                      'faction_banner',
                      'dragon_card',
                      'fatebreaker_title',
                      'secret_codex',
                      'trophy_card'
                    ].includes(keyOrArtifact) ? 'chapter_seal' : 'rank_up';

    milestoneName = keyOrArtifact === 'chapter_seal' ? 'Sealed a Story Chapter' :
                    keyOrArtifact === 'challenge_complete' ? 'Fate Survival Complete' :
                    keyOrArtifact === 'chapter_5' ? 'Ascended to Chapter 5' :
                    keyOrArtifact === 'legendary_sword' ? 'Acquired Legendary Sword' :
                    keyOrArtifact === 'boss_fight' ? 'Confronted Primordial Nemesis' :
                    keyOrArtifact === 'bond_token' ? 'Earned Sworn Allegiance' :
                    keyOrArtifact === 'faction_banner' ? 'Triumph in Sect War' :
                    keyOrArtifact === 'dragon_card' ? 'Manifested Cosmic Dragon' :
                    keyOrArtifact === 'fatebreaker_title' ? 'Shattered predetermined Fate' :
                    keyOrArtifact === 'secret_codex' ? 'Discovered Secret Codex' :
                    keyOrArtifact === 'trophy_card' ? 'Slain the Tyrant Lord' :
                    'Attained Dao Rank';

    baseArtifact = {
      name: template.name,
      description: template.description,
      milestoneType,
      milestoneName,
      rarity: template.rarity,
      attributeBoost: template.attributeBoost,
      sourceStoryId: sourceId,
      sourceStoryTitle: sourceTitle
    };
  } else {
    baseArtifact = keyOrArtifact;
  }

  const id = `art-${artifactKey || 'custom'}-${Date.now()}`;
  const newArtifact: CosmicArtifact = {
    ...baseArtifact,
    id,
    unlockedAt: now
  };

  // Check duplicates to avoid multi-award
  const checkDuplicate = (list: CosmicArtifact[]) => {
    if (artifactKey) {
      return list.some(a => a.name === newArtifact.name);
    }
    return list.some(a => a.name === newArtifact.name && a.sourceStoryId === newArtifact.sourceStoryId);
  };

  if (user) {
    try {
      const userRef = doc(db, 'users', user.uid);
      const uDoc = await getDoc(userRef);
      if (uDoc.exists()) {
        const data = uDoc.data();
        const currentInventory: CosmicArtifact[] = data.inventory || data.cosmicInventory || [];

        if (checkDuplicate(currentInventory)) {
          return null; // Already unlocked
        }

        const updatedInventory = [...currentInventory, newArtifact];
        await setDoc(userRef, { cosmicInventory: updatedInventory, inventory: updatedInventory }, { merge: true });

        // Dispatch window event for live-unlock celebration UI
        window.dispatchEvent(new CustomEvent('seihouse-artifact-unlocked', { detail: { artifact: newArtifact } }));
        return newArtifact;
      }
    } catch (e) {
      console.error('Failed to save artifact to Cloud:', e);
    }
  }

  // Local fallback (Offline or Guest Mode)
  try {
    const localInvStr = localStorage.getItem('seihouse-local-cosmic-inventory');
    const currentInventory: CosmicArtifact[] = localInvStr ? JSON.parse(localInvStr) : [];

    if (checkDuplicate(currentInventory)) {
      return null; // Already unlocked
    }

    const updatedInventory = [...currentInventory, newArtifact];
    localStorage.setItem('seihouse-local-cosmic-inventory', JSON.stringify(updatedInventory));

    // Also update local store userProfile if we are offline/guest
    const localProfile = useAppStore.getState().userProfile;
    if (localProfile) {
      useAppStore.setState({
        userProfile: {
          ...localProfile,
          cosmicInventory: updatedInventory,
          inventory: updatedInventory
        }
      });
    } else {
      // Initialize offline dummy profile
      useAppStore.setState({
        userProfile: {
          uid: 'anonymous',
          username: 'Mortal Reader',
          displayName: 'Mortal Reader',
          avatarUrl: '',
          preferredLanguage: 'English',
          defaultTranslationLanguage: 'English',
          savedStoryCount: 0,
          activeStories: [],
          inactiveStories: [],
          joinedDate: now,
          updatedAt: now,
          cosmicInventory: updatedInventory,
          inventory: updatedInventory
        }
      });
    }

    window.dispatchEvent(new CustomEvent('seihouse-artifact-unlocked', { detail: { artifact: newArtifact } }));
    return newArtifact;
  } catch (e) {
    console.error('Failed to save artifact locally:', e);
  }

  return null;
}

export async function getUnlockedArtifacts(): Promise<CosmicArtifact[]> {
  const user = auth.currentUser;
  if (user) {
    try {
      const uDoc = await getDoc(doc(db, 'users', user.uid));
      if (uDoc.exists()) {
        const data = uDoc.data();
        return data.inventory || data.cosmicInventory || [];
      }
    } catch (e) {
      console.error('Failed to fetch artifacts from Cloud:', e);
    }
  }
  const localInvStr = localStorage.getItem('seihouse-local-cosmic-inventory');
  return localInvStr ? JSON.parse(localInvStr) : [];
}

/**
 * Checks and awards milestone artifacts based on current state.
 */
export function checkAndAwardRankArtifacts(rank: string): void {
  const rankKeyMap: Record<string, string> = {
    'Wandering Disciple': 'wandering_disciple',
    'Outer Sect Scribe': 'outer_sect_scribe',
    'Inner Sect Scholar': 'inner_sect_scholar',
    'Dao Adept': 'dao_adept',
    'Spirit Author': 'spirit_author',
    'Heavenly Chronicler': 'heavenly_chronicler',
    'Sage of Branching Paths': 'sage_branching',
    'Dao Master': 'dao_master'
  };

  const key = rankKeyMap[rank];
  if (key) {
    unlockCosmicArtifact(key).catch(err => {
      console.error(`Failed to automatically award rank artifact for ${rank}:`, err);
    });
  }
}

export async function scanChapterForArtifacts(
  storyId: string,
  storyTitle: string,
  chapterNumber: number,
  text: string,
  metadata?: any
): Promise<void> {
  const normalized = text.toLowerCase();

  const statsMsg = (metadata?.statsChangeMessage || "").toLowerCase();
  const cuePayload = metadata?.cuePayload;
  const blocks = metadata?.blocks || [];

  // 1. Arc Entry Reward (Minor Relic / Badge / Codex Stamp) - 1 every arc (early arc)
  // Assuming an arc is roughly 6 chapters. We trigger this on chapter 1, 7, 13, etc.
  if (chapterNumber % 6 === 1) {
    let zoneName = "New Territory";
    // Try to find a location entity
    const locationEntity = blocks.flatMap((b: any) => b.metadata?.entities || []).find((e: any) => e.type === 'location' || e.type === 'faction');
    if (locationEntity && locationEntity.name) {
      zoneName = locationEntity.name;
    }
    await unlockCosmicArtifact({
      name: `Codex Stamp: Entered ${zoneName}`,
      description: `A minor relic confirming your entry into ${zoneName}. It resonates with the local Qi.`,
      rarity: 'Common',
      attributeBoost: '+5% Environmental Affinity',
      sourceStoryId: storyId,
      sourceStoryTitle: storyTitle,
      milestoneType: 'chapter_seal',
      milestoneName: 'Arc Entry'
    }, storyId, storyTitle);
  }

  // 2. Arc Climax Reward (Arc Relic) - 1 per arc
  // We trigger this around chapter 5, 11, 17, etc.
  if (chapterNumber % 6 === 5) {
    let relicName = "Fragment of the Unknown Core";
    // Try to find an artifact or beast entity
    const climaxEntity = blocks.flatMap((b: any) => b.metadata?.entities || []).find((e: any) => e.type === 'artifact' || e.type === 'beast');
    if (climaxEntity && climaxEntity.name) {
      relicName = climaxEntity.name;
    }
    await unlockCosmicArtifact({
      name: `Relic Acquired: ${relicName}`,
      description: `The main reward of this arc. The heavy emotional payoff from surviving the climax.`,
      rarity: 'Epic',
      attributeBoost: '+15% Arc Resonance',
      sourceStoryId: storyId,
      sourceStoryTitle: storyTitle,
      milestoneType: 'challenge_complete',
      milestoneName: 'Arc Climax'
    }, storyId, storyTitle);
  }

  // 3. Boss Scene / Major Audio (Manifestation Card)
  const isBossScene = 
    normalized.includes('boss fight') ||
    normalized.includes('villain') ||
    normalized.includes('dragon roar') ||
    (cuePayload?.danger && cuePayload.danger > 75) ||
    blocks.some((b: any) => b.metadata?.sceneType === 'boss-fight' || b.metadata?.danger > 8);

  if (isBossScene) {
    await unlockCosmicArtifact({
      name: "Manifestation Card: Adversary's Roar",
      description: "A major manifestation card captured from a powerful adversary or boss scene.",
      rarity: 'Legendary',
      attributeBoost: '+20% Combat Will',
      sourceStoryId: storyId,
      sourceStoryTitle: storyTitle,
      milestoneType: 'chapter_seal',
      milestoneName: 'Boss Confrontation'
    }, storyId, storyTitle);
  }

  // 4. Optional Hidden Reward (Secret Title / Condition)
  // Triggered by secrets, specific prompt types, or fate survival
  const hasHiddenSecret = 
    normalized.includes('secret') || 
    normalized.includes('hidden') || 
    normalized.includes('perfect survival') ||
    blocks.some((b: any) => b.system?.promptType === 'mystery' || b.system?.promptType === 'fate_event');

  if (hasHiddenSecret) {
    let secretName = "One Who Walked the Hidden Path";
    const mysteryEntity = blocks.flatMap((b: any) => b.metadata?.entities || []).find((e: any) => e.type === 'mystery' || e.type === 'artifact');
    if (mysteryEntity && mysteryEntity.name) {
      secretName = `Secret Title: Witness of ${mysteryEntity.name}`;
    }
    await unlockCosmicArtifact({
      name: secretName,
      description: "An optional hidden reward for uncovering a secret, making a special choice, or surviving a tough fate route.",
      rarity: 'Epic',
      attributeBoost: '+15% Truth Comprehension',
      sourceStoryId: storyId,
      sourceStoryTitle: storyTitle,
      milestoneType: 'challenge_complete',
      milestoneName: 'Hidden Secret'
    }, storyId, storyTitle);
  }

  // 5. Mythic / Profile-defining Relic (1 every 3-5 arcs -> ~every 24 chapters)
  if (chapterNumber % 24 === 0 && chapterNumber > 0) {
    await unlockCosmicArtifact({
      name: "Heaven-Defying Fatebreaker Seal",
      description: "A mythic relic defining your profile, awarded for surviving multiple arduous arcs and defying fate itself.",
      rarity: 'Mythic',
      attributeBoost: '+30% Fate Resistance',
      sourceStoryId: storyId,
      sourceStoryTitle: storyTitle,
      milestoneType: 'rank_up',
      milestoneName: 'Saga Milestone'
    }, storyId, storyTitle);
  }

  // 6. Legendary Completion Title (1 per major saga -> ~every 60 chapters)
  if (chapterNumber % 60 === 0 && chapterNumber > 0) {
    await unlockCosmicArtifact({
      name: "Legendary Title: Witness of the Grand Saga",
      description: "A legendary completion title. You have witnessed the rise and fall of sects, empires, and gods across a major saga.",
      rarity: 'Transcendent',
      attributeBoost: '+50% Dao Comprehension',
      sourceStoryId: storyId,
      sourceStoryTitle: storyTitle,
      milestoneType: 'rank_up',
      milestoneName: 'Saga Completion'
    }, storyId, storyTitle);
  }

  // Scan for newly-forged unique artifacts in the blocks
  for (const block of blocks) {
    if (block.worldCard?.entityType === 'artifact' && block.worldCard.entityName) {
      await unlockCosmicArtifact({
        name: block.worldCard.entityName,
        description: block.worldCard.quote || `A rare and powerful relic of historical significance, manifested from the fate lines of your story.`,
        rarity: 'Epic',
        attributeBoost: `+15% ${block.worldCard.entityName} Resonance`,
        sourceStoryId: storyId,
        sourceStoryTitle: storyTitle
      }, storyId, storyTitle);
    }
  }
}

import { StoryBlockMetadata } from '../../types';

export interface SceneAudioTrack {
  id: string;          // e.g., 'FIGHTING_1_TOURNAMENT', 'BOSS_FIGHT_1_FINAL_BOSS'
  mood: string;        // 'fighting', 'boss-fight', 'adventure', etc.
  tags: string[];      // Context matching tags (e.g., 'tournament', 'cave')
  url: string;         // Cloudflare R2 string link
  isPremium: boolean;  // Mark user-generated or premium track explicitly
}

// 1. Priority Map
// When multiple narrative blocks occur in the same chapter or scene window, 
// the Highest Priority mood takes over the soundscape. 
export const MOOD_PRIORITIES: Record<string, number> = {
  'boss-fight': 100,
  'tragedy': 95,
  'fighting': 90,
  'duel': 88,
  'war': 85,
  'triumph': 80,
  'horror': 75,
  'dread': 72,
  'tension': 70,
  'excitement': 65,
  'tribulation': 60,
  'adventure': 50,
  'mystery': 40,
  'travel': 30,
  'romance': 25,
  'sad': 20,
  'mystical': 15,
  'serenity': 10,
  'ambient': 5,
  'tired': 1,
};

// 2. Dummy Skeleton Library 
// You will replace this with your dynamic fetch to Cloudflare when ready
export const TRACK_LIBRARY: SceneAudioTrack[] = Object.keys(MOOD_PRIORITIES).map((mood, idx) => ({
  id: `${mood.toUpperCase().replace('-', '_')}_1_DEFAULT`,
  mood,
  tags: ['default'],
  url: '', 
  isPremium: false,
}));

// 3. Audio Resolution Controller
export class SceneScoreEngine {
  private currentTrackId: string | null = null;
  private currentPriority: number = -1;

  public evaluateSceneContext(
    musicMeta: StoryBlockMetadata['music'], 
    sceneTags: string[] = []
  ): SceneAudioTrack | null {
    if (!musicMeta) return null;

    const requestedMood = musicMeta.mood;
    const moodPriority = MOOD_PRIORITIES[requestedMood] || 0;

    // RULE 1: STRICT OVERRIDE PRIORITY
    // Only switch tracks if the new narrative cue has a higher or equal priority 
    // to the currently playing track. (e.g., Boss Fight overrides Adventure)
    if (moodPriority < this.currentPriority) {
        return null; // Ignore lower priority background noise once tension is escalated
    }

    // RULE 2: SPECIFIC TRACK OVERRIDE
    // If LLM or user manually requests a specific custom premium track ID, immediately respect it.
    if (musicMeta.trackId) {
      const explicitTrack = TRACK_LIBRARY.find(t => t.id === musicMeta.trackId);
      if (explicitTrack) {
        this.updateState(explicitTrack.id, moodPriority);
        return explicitTrack;
      }
    }

    // RULE 3: CONTEXT MATCHING
    // Find tracks matching mood. If multiple match, score them against scene environment tags.
    const candidates = TRACK_LIBRARY.filter(t => t.mood === requestedMood);

    if (candidates.length === 0) return null;

    let bestMatch = candidates[0];
    let highestScore = -1;

    for (const track of candidates) {
      let score = 0;
      // Boost score based on overlapping tags (e.g. ['cave', 'dark'] intersecting with scene tags)
      for (const tag of track.tags) {
        if (sceneTags.includes(tag)) score += 2;
      }

      if (score > highestScore) {
        highestScore = score;
        bestMatch = track;
      }
    }

    this.updateState(bestMatch.id, moodPriority);
    return bestMatch;
  }

  // Gracefully drop priority (e.g., moving to the next chapter) so lower priority songs can play again
  public resetScene() {
    this.currentTrackId = null;
    this.currentPriority = -1;
  }

  private updateState(trackId: string, priority: number) {
    this.currentTrackId = trackId;
    this.currentPriority = priority;
  }
}

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { encryptKey, decryptKey, secureStorage } from './encryption';

describe('encryption', () => {
  beforeEach(() => {
    localStorage.clear();
  });

  describe('encryptKey and decryptKey', () => {
    it('returns empty string for empty input', async () => {
      expect(await encryptKey('')).toBe('');
      expect(await decryptKey('')).toBe('');
    });

    it('returns unencrypted value if not encrypted', async () => {
      expect(await decryptKey('plain text')).toBe('plain text');
    });

    it('encrypts and decrypts a value', async () => {
      const plainText = 'super-secret-api-key';
      const encrypted = await encryptKey(plainText);
      expect(encrypted).not.toBe(plainText);
      expect(encrypted.startsWith('enc::')).toBe(true);

      const decrypted = await decryptKey(encrypted);
      expect(decrypted).toBe(plainText);
    });
  });

  describe('secureStorage', () => {
    it('setItem and getItem work correctly', async () => {
      const key = 'test-key';
      const value = 'secret-value';

      await secureStorage.setItem(key, value);
      const retrieved = await secureStorage.getItem(key);
      expect(retrieved).toBe(value);

      const raw = localStorage.getItem(key);
      expect(raw).not.toBe(value);
      expect(raw?.startsWith('enc::')).toBe(true);
    });

    it('removeItem works', async () => {
      const key = 'test-key';
      const value = 'secret-value';

      await secureStorage.setItem(key, value);
      secureStorage.removeItem(key);
      expect(await secureStorage.getItem(key)).toBe('');
    });

    it('setItem removes item if value is empty', async () => {
      const key = 'test-key';
      await secureStorage.setItem(key, 'value');
      await secureStorage.setItem(key, '');
      expect(localStorage.getItem(key)).toBeNull();
    });
  });
});

/**
 * SEIHouse Client-Side Key Obfuscation & Telemetry Scrambler.
 * 
 * ARCHITECTURAL WARNING & DISCLAIMER:
 * This module implements local shoulder-surfing protection and client-side key scrambling (obfuscation),
 * NOT authentic or hardened server-side cryptographic security. It derives a client-side AES-GCM key by hashing 
 * local device telemetry (User Agent, platform, language) as a dynamic salt. 
 * 
 * While this serves as a lightweight, frictionless approach for locally-persistent, Bring-Your-Own-Key (BYOK) 
 * configurations where a dedicated hardware security module (HSM) or secure server-side vault is not available,
 * it is fundamentally an *obfuscation* mechanism, not a military-grade security boundary. 
 * 
 * The export names (`secureStorage`, `encryptKey`, `decryptKey`) are preserved purely to maintain backwards-compatibility
 * with callers throughout the codebase, but they should be treated strictly as client-side telemetry-derived local scramblers.
 */

const getEntropyString = (): string => {
  if (typeof window === "undefined") return "seihouse-celestial-key";
  const userAgent = window.navigator?.userAgent || "";
  const platform = window.navigator?.platform || "";
  const language = window.navigator?.language || "";
  return `seihouse-obfuscated-salt-04acff:${userAgent}:${platform}:${language}`;
};

const getCryptoKey = async (): Promise<CryptoKey> => {
  const entropy = getEntropyString();
  const encoder = new TextEncoder();
  const keyMaterial = await crypto.subtle.digest("SHA-256", encoder.encode(entropy));
  return crypto.subtle.importKey(
    "raw",
    keyMaterial,
    { name: "AES-GCM" },
    false,
    ["encrypt", "decrypt"]
  );
};

function legacyDecrypt(encryptedValue: string): string {
  try {
    const rawEntropy = getEntropyString();
    let hash = 0;
    for (let i = 0; i < rawEntropy.length; i++) {
      const char = rawEntropy.charCodeAt(i);
      hash = (hash << 5) - hash + char;
      hash = hash & hash;
    }
    const secret = Math.abs(hash).toString(36) + "-portal-key";
    const rawBase64 = encryptedValue.substring(5);
    const binary = atob(rawBase64);
    const encryptedBytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) {
      encryptedBytes[i] = binary.charCodeAt(i);
    }

    const secretBytes = new TextEncoder().encode(secret);
    const decryptedBytes = new Uint8Array(encryptedBytes.length);
    for (let i = 0; i < encryptedBytes.length; i++) {
      decryptedBytes[i] = encryptedBytes[i] ^ secretBytes[i % secretBytes.length];
    }

    return new TextDecoder().decode(decryptedBytes);
  } catch (error) {
    return "";
  }
}

/**
 * Encrypts a string value using AES-GCM with a dynamic key.
 */
export async function encryptKey(value: string): Promise<string> {
  if (!value) return "";
  try {
    const key = await getCryptoKey();
    const iv = crypto.getRandomValues(new Uint8Array(12));
    const encoded = new TextEncoder().encode(value);
    const ciphertext = await crypto.subtle.encrypt(
      { name: "AES-GCM", iv },
      key,
      encoded
    );

    // Convert to base64
    const ivBase64 = btoa(String.fromCharCode(...iv));
    const cipherBase64 = btoa(String.fromCharCode(...new Uint8Array(ciphertext)));
    return `enc::${ivBase64}:${cipherBase64}`;
  } catch (error) {
    console.error("[Encryption Error]", error);
    return "";
  }
}

/**
 * Decrypts a string value that was encrypted using encryptKey.
 */
export async function decryptKey(encryptedValue: string): Promise<string> {
  if (!encryptedValue) return "";
  if (!encryptedValue.startsWith("enc::")) {
    // Unencrypted
    return encryptedValue;
  }

  const parts = encryptedValue.substring(5).split(':');
  if (parts.length === 1) {
    // Legacy XOR fallback
    return legacyDecrypt(encryptedValue);
  }

  try {
    const ivBytes = Uint8Array.from(atob(parts[0]), c => c.charCodeAt(0));
    const cipherBytes = Uint8Array.from(atob(parts[1]), c => c.charCodeAt(0));

    const key = await getCryptoKey();
    const decrypted = await crypto.subtle.decrypt(
      { name: "AES-GCM", iv: ivBytes },
      key,
      cipherBytes
    );

    return new TextDecoder().decode(decrypted);
  } catch (error) {
    console.error("[Encryption Error] Failed to decrypt client-side credential:", error);
    return "";
  }
}

/**
 * Enhanced secure wrapper for localStorage API key operations
 */
export const secureStorage = {
  async setItem(key: string, value: string): Promise<void> {
    try {
      if (!value) {
        localStorage.removeItem(key);
        return;
      }
      const encrypted = await encryptKey(value);
      localStorage.setItem(key, encrypted);
    } catch (error) {
      console.warn('Failed to save to secureStorage:', error);
    }
  },

  async getItem(key: string): Promise<string> {
    if (typeof window === "undefined") return "";
    const raw = localStorage.getItem(key);
    if (!raw) return "";
    return decryptKey(raw);
  },

  removeItem(key: string): void {
    if (typeof window !== "undefined") {
      localStorage.removeItem(key);
    }
  }
};

import { doc, setDoc, increment, collection, addDoc, query, where, getDocs, Timestamp, getDoc } from 'firebase/firestore';
import { db, auth } from './firebase';
